// accountOpDisabled reports whether an op key is in the account's DisabledOps JSON.
func accountOpDisabled(acc entity.ConnectorAccount, opKey string) bool {
	if acc.DisabledOps == "" {
		return false
	}
	return strings.Contains(acc.DisabledOps, `"`+opKey+`"`)
}

